const CONTENT = {"disclaimer": "This guide is for educational purposes and general skincare habits. It is not medical advice. If you have a diagnosed skin condition, are considering prescription-strength actives, or have a persistent issue that isn't responding to basic changes, see a dermatologist.", "sections": [{"num": 0, "id": "section-0", "code": "S00", "title": "THE CTP SYSTEM", "category": "FOUNDATION", "short": "THE CTP SYSTEM", "intro": [], "subs": [{"title": "Welcome", "blocks": [{"type": "p", "text": "Most people overcomplicate skincare. Ten-step routines, seasonal product swaps, \"glow serums,\" \"detox masks,\" ingredients with names you can't pronounce and effects you can't measure. None of it is necessary, and most of it is actively working against you — either by doing nothing, or by irritating skin that was fine to begin with."}, {"type": "p", "text": "This guide strips skincare down to what actually moves the needle. It's built around one framework: **CTP — Cleanse, Treat, Protect.** Three steps. That's it. Everything genuinely effective in skincare fits inside these three categories, and almost everything marketed to you sits outside them, dressed up to look essential."}, {"type": "p", "text": "Later in this guide, there's a section bluntly titled \"99% of the Skincare Market Is a Scam.\" That's not clickbait — it's the operating principle behind everything here. Once you understand CTP and learn to choose ingredients instead of products, you'll be equipped to walk past 99% of what's marketed at you and know, immediately, whether it's worth your money."}]}, {"title": "The Only Skincare You Need: CTP", "blocks": [{"type": "p", "text": "**CTP stands for Cleanse, Treat, Protect**, and together these three steps cover roughly 99% of what an effective skincare routine needs to do. Everything else — toners with no active ingredients, essences, \"boosters,\" mists, multi-step layering rituals — is optional at best and noise at worst."}, {"type": "p", "text": "**Cleanse** is universal and non-negotiable. Everyone needs to remove dirt, oil, sweat, and sunscreen from their skin, and everyone needs to do it gently. There's no version of \"good skin\" that skips this."}, {"type": "p", "text": "**Treat** is the customization layer — and it's optional. If you have no active skin concerns, you can skip it entirely. If you do have a concern (acne, pigmentation, dryness, aging, redness, scarring), this is where you address it, using specific ingredients matched to that concern."}, {"type": "p", "text": "**Protect** is, without exaggeration, the most important of the three. It's also the most skipped. Daily sunscreen is the single highest-leverage thing you can do for your skin, full stop — and it's covered in depth below."}, {"type": "p", "text": "Section 1 below is the system in full. Section 2, right after it, is why you can safely ignore almost everything else you've been told you need."}]}]}, {"num": 1, "id": "section-1", "code": "S01", "title": "STEP 1 — CLEANSE", "category": "CLEANSE", "short": "CLEANSE", "intro": [{"type": "p", "text": "Cleansing is foundational — and it's also the step most over-marketed and over-engineered. Brands sell \"deep cleansing,\" \"pore-clearing,\" \"detoxifying\" formulas as if your skin is something that needs aggressive intervention twice a day. It isn't. Cleansing exists to remove what's sitting on top of your skin, gently, so the rest of your routine (and your skin itself) can function properly."}], "subs": [{"title": "When to Cleanse: Three Timing Rules", "blocks": [{"type": "list", "ordered": true, "items": ["**Once you wake up.** Overnight, oil and sweat accumulate on your skin even if nothing else has touched it. Start the day clean.", "**Whenever you come in from outdoors, after sweating, or when you feel like it.** If you've been outside, exercised, or just feel like your skin needs a reset, a cleanse is appropriate — there's no rigid rule here beyond \"don't overdo it.\"", "**Before sleep / in the evening.** This is the most important cleanse of the day. Sunscreen, makeup, pollution, and a full day of oil production need to come off before you sleep — sleeping in this layer is one of the most common (and avoidable) skin mistakes."]}, {"type": "p", "text": "For most people, that's twice a day — morning and night — with occasional extra cleanses based on activity. More than that, and you risk stripping your skin's natural barrier."}]}, {"title": "How to Cleanse: Technique Matters", "blocks": [{"type": "p", "text": "Use slow, circular massage motions with clean hands. That's it. **Do not use scrubbers** — no brushes, no exfoliating mitts, no textured sponges. **Do not physically scrub your skin.** Physical exfoliation tools cause micro-tears in the skin barrier, and the \"squeaky clean\" feeling they produce is often a sign of damage, not cleanliness."}]}, {"title": "What to Cleanse With", "blocks": [{"type": "p", "text": "This is where label language matters more than people realize."}, {"type": "list", "ordered": false, "items": ["Look for products explicitly labeled **\"cleanser\"** rather than **\"face wash.\"** This isn't just semantics — \"cleanser\" formulations tend to be gentler and more skin-barrier-conscious as a category.", "If you're using a face wash, look for ones labeled **\"hydrating,\" \"gentle,\"** or **\"light.\"** These modifiers signal a formula that won't strip your skin.", "**Avoid:** physical scrubbers, harsh or \"strong\" formulas, anything marketed as **\"dirt removing\"** or **\"pollution removing.\"** These are marketing terms designed to make you feel like your skin is dirty in a way that requires aggressive chemistry to fix. It doesn't."]}, {"type": "p", "text": "**The hierarchy, simplified:** gentle cleansers > regular cleansers > hydrating face wash > face wash. When in doubt, pick whichever option on this list is gentlest and gets the job done — that's almost always the right call."}]}]}, {"num": 2, "id": "section-2", "code": "S02", "title": "STEP 2 — TREAT", "category": "TREAT", "short": "TREAT", "intro": [{"type": "p", "text": "This is the largest section of the guide, and for good reason — it's where your routine actually gets personal. But the most important sentence in this entire section is this: **if you have no active skin concerns, skip this step entirely.** Cleanse and Protect alone are enough for clear, healthy skin with no specific issues. Treat exists to solve problems, not to be used by default."}], "subs": [{"title": "Step (i): Analyze", "blocks": [{"type": "p", "text": "Before choosing anything, be honest about what's actually going on with your skin. Not what an ad told you might be wrong, not what a filter made you notice — what's actually present. Common categories: active breakouts, leftover marks/scars from old breakouts, uneven tone or patches of pigmentation, persistent dryness or flaking, visible redness or irritation, and early signs of aging (fine lines, loss of firmness, dullness)."}, {"type": "p", "text": "Most people have one, maybe two, real concerns. If you're listing five or six, take a step back — some of those are likely perceived rather than actual, often shaped by marketing that's trained you to see \"problems\" that don't need solving."}]}, {"title": "Step (ii): Choose Ingredients, Not Products", "blocks": [{"type": "p", "text": "This is the philosophical core of the entire guide, so it's worth understanding *why* it matters, not just accepting it as a rule."}, {"type": "p", "text": "Every skincare product is a delivery vehicle for a small number of active ingredients, wrapped in a base formula, priced with a margin, and sold with a story. A $60 \"brightening serum\" and a $12 one might contain the same active ingredient at a similar concentration — the difference is packaging, marketing, and margin. When you know the ingredient that addresses your concern, you can evaluate *any* product in seconds: check the ingredient list, check the concentration if it's listed, and ignore everything else on the label."}, {"type": "p", "text": "This single shift — from \"what product should I buy\" to \"what ingredient does my concern need\" — is what separates people who spend years and hundreds of dollars chasing \"the right routine\" from people who fix their concern in a few months with two or three products."}]}, {"title": "The Concern-to-Ingredient Map", "blocks": [{"type": "p", "text": "Below is the map. For each concern, these are the ingredients with real, evidence-backed effects. Everything else marketed for these concerns is, at best, a minor supporting player."}, {"type": "p", "text": "**Acne / Pimples** Active breakouts are driven by a combination of excess oil, clogged pores, bacteria, and inflammation. The ingredients below address different parts of that chain:"}, {"type": "list", "ordered": false, "items": ["**Benzoyl peroxide** — kills acne-causing bacteria directly. Typical strengths: 5% for the face, up to 10% for body acne (back, chest), where skin is less sensitive.", "**Salicylic acid** — a BHA that exfoliates inside pores, helping clear blockages. Often available even in face washes at low concentrations for daily use.", "**Clindamycin** — a topical antibiotic, typically prescription, used for more stubborn or inflammatory acne.", "**Retinoids** — normalize skin cell turnover, preventing pores from clogging in the first place. Covered in depth later as the guide's MVP ingredient.", "**Azelaic acid** — reduces inflammation and bacteria while also helping with post-acne marks; a gentler option for sensitive skin."]}, {"type": "p", "text": "**Pigmentation / Tanning (Complexion Fix) — the MVP category** This is the category where one ingredient matters more than all the others combined:"}, {"type": "list", "ordered": false, "items": ["**Sunscreen** — by far the most important ingredient for this concern. Every other ingredient on this list is fighting against pigmentation; unprotected sun exposure actively creates more of it. Skipping sunscreen while treating pigmentation is working against yourself.", "**Hydroquinone** — a strong skin-lightening agent for stubborn dark spots, typically used short-term and often at prescription strength; not a long-term daily ingredient.", "**Lactic acid** — an AHA that gently exfoliates and brightens, well-tolerated by most skin types.", "**Vitamin C** — an antioxidant that brightens tone and helps fade dark spots over time, with the added benefit of supporting sunscreen's UV defense.", "**Retinoids** — accelerate cell turnover, helping pigmented cells shed faster and new, evener-toned skin take their place.", "**Kojic acid** — another tyrosinase-inhibiting brightening ingredient, often paired with the others above in combination formulas."]}, {"type": "p", "text": "**Dry Skin** Dryness is usually a barrier problem — either not enough moisture, not enough oil to lock it in, or both:"}, {"type": "list", "ordered": false, "items": ["**Ceramides** — lipids that are a natural part of your skin barrier; topical ceramides help repair and reinforce it.", "**Mineral oil** — an effective, inexpensive occlusive that locks moisture in; despite its reputation, it's well-tolerated by most skin types.", "**Petrolatum** — the gold standard occlusive, especially for very dry or compromised skin.", "**Hyaluronic acid** — a humectant that draws and holds water in the skin; works best applied to damp skin and sealed with a moisturizer.", "**Vitamin E** — an antioxidant often paired with moisturizing formulas, supporting overall skin barrier health."]}, {"type": "p", "text": "**Scarring** Scarring is the most stubborn category here, and the one most likely to need professional input:"}, {"type": "list", "ordered": false, "items": ["**High-strength retinoid creams** — prescription-strength retinoids can meaningfully improve texture and the appearance of scarring over months of consistent use.", "**Deep chemical peels** — professionally administered peels can address scarring more aggressively than anything available over the counter; this is a dermatologist-office category, not a home routine one."]}, {"type": "p", "text": "**Redness** Redness is typically inflammation- or sensitivity-driven:"}, {"type": "list", "ordered": false, "items": ["**Aloe vera** — a gentle, soothing ingredient that calms irritated skin with minimal risk of further irritation.", "**Niacinamide** — reduces inflammation and supports barrier function; one of the best-tolerated active ingredients across skin types.", "**Azelaic acid** — appears again here for its anti-inflammatory properties, doing double duty for acne and redness."]}, {"type": "p", "text": "**Aging** This category isn't just for people over 30 — and that framing matters:"}, {"type": "list", "ordered": false, "items": ["**Retinoids** — the single most effective anti-aging ingredient available, by a wide margin.", "**Sunscreen** — UV exposure is the single largest controllable contributor to visible aging. This isn't a secondary mention; it belongs at the top of any anti-aging conversation.", "**Copper peptides (and other peptides)** — support skin firmness and repair over time, often used alongside retinoids."]}, {"type": "p", "text": "If you're in your twenties and skipped this category because \"aging isn't a concern yet\" — that's exactly the right time to start. Prevention is dramatically easier than correction."}]}, {"title": "Building a Treatment Routine", "blocks": [{"type": "p", "text": "Once you've identified your concern(s) and matched them to ingredients, three rules keep your routine safe and effective:"}, {"type": "list", "ordered": true, "items": ["**Don't stack two active ingredients carelessly.** Some combinations (like retinoids and certain acids) can over-irritate skin if used together without understanding how they interact. When in doubt, separate them.", "**Separate AM and PM appropriately.** Sunscreen and antioxidants (like Vitamin C) generally belong in the morning; retinoids and most exfoliating acids generally belong at night, partly because some increase sun sensitivity.", "**Don't overload with ingredients.** More actives isn't more effective — it's more irritation risk. Pick the one or two ingredients that address your actual concern and give them time to work before adding more."]}]}, {"title": "Three Example Routines", "blocks": [{"type": "p", "text": "**Routine 1 — Male, mid-20s, acne + early pigmentation**"}, {"type": "list", "ordered": false, "items": ["**AM:** Gentle cleanser → Vitamin C serum → Sunscreen (SPF 50+)", "**PM:** Gentle cleanser → Salicylic acid (2% BHA, 3–4x/week) → Niacinamide moisturizer", "*Logic:* Vitamin C and sunscreen handle pigmentation prevention during the day; salicylic acid targets active breakouts at night without stacking onto the AM antioxidant step."]}, {"type": "p", "text": "**Routine 2 — Male, early 30s, aging + dryness**"}, {"type": "list", "ordered": false, "items": ["**AM:** Hydrating cleanser → Hyaluronic acid (on damp skin) → Moisturizer with ceramides → Sunscreen (SPF 50+)", "**PM:** Hydrating cleanser → Retinoid (start low strength, 2–3x/week) → Rich moisturizer with petrolatum or mineral oil", "*Logic:* The AM routine builds and locks in hydration before sun protection; the PM retinoid addresses aging directly, buffered by a heavier moisturizer to manage dryness and minimize irritation."]}, {"type": "p", "text": "**Routine 3 — Female, late 20s, redness + sensitivity + occasional breakouts**"}, {"type": "list", "ordered": false, "items": ["**AM:** Gentle cleanser → Niacinamide serum → Lightweight moisturizer → Sunscreen (SPF 50+, mineral)", "**PM:** Gentle cleanser → Azelaic acid (2–3x/week) → Light moisturizer", "*Logic:* Niacinamide and azelaic acid both calm redness while azelaic acid pulls double duty on occasional breakouts; everything here is chosen for being well-tolerated by sensitive skin, with mineral sunscreen reducing irritation risk further."]}, {"type": "p", "text": "These aren't prescriptions — they're worked examples. Swap ingredients within the same concern category as needed, and adjust frequency based on how your skin responds."}]}, {"title": "Post-Treatment: Tapering & Maintenance", "blocks": [{"type": "p", "text": "Once a concern is resolved — pigmentation has faded, breakouts have cleared, redness has calmed — don't keep running aggressive actives indefinitely at the same intensity. **Taper off**, especially with acids and peels, which can over-exfoliate skin that no longer needs correcting."}, {"type": "p", "text": "That doesn't mean dropping Treat entirely, though. For people in good, stable skin condition, a **light, standing treatment habit** — a regular Vitamin C routine, or a maintained low-frequency retinoid habit — keeps skin in good shape and helps prevent the concern from returning, without the intensity of an active correction phase."}]}]}, {"num": 3, "id": "section-3", "code": "S03", "title": "STEP 3 — PROTECT", "category": "PROTECT", "short": "PROTECT", "intro": [{"type": "p", "text": "If you take away exactly one thing from this entire guide, take this: **wear sunscreen, every single day.**"}, {"type": "p", "text": "Here's why this step outranks everything else. UV exposure actively undoes progress from the Treat step — it's a direct contributor to pigmentation, a major driver of visible aging, and it increases the risk of skin cancer. If you're using actives like retinoids or acids, your skin becomes *more* sensitive to UV, not less. Using powerful treatment ingredients without daily sunscreen isn't just suboptimal — it's the single worst mistake you can make in a skincare routine, because you're actively working against the thing you're trying to fix."}], "subs": [{"title": "The Sunscreen Protocol — Non-Negotiable Rules", "blocks": [{"type": "list", "ordered": false, "items": ["**SPF 50 or above.** Don't go lower as a default.", "**Apply first thing after cleansing in the morning** — before anything else, or as the final step of your AM routine depending on formula, but always as a core morning habit.", "**Reapply every ~2 hours**, especially with continued sun exposure.", "**Reapply after sweating or water activity** — sunscreen doesn't survive a swim or a hard workout.", "**Physical (mineral) sunscreens are generally preferable** — they tend to be gentler on sensitive or actives-treated skin and start working immediately on application.", "**365 days a year, including indoors.** UV exposure through windows, and especially blue light/UV from extended screen exposure combined with ambient daylight, adds up. \"It's cloudy\" or \"I'm inside\" isn't a reason to skip it."]}, {"type": "p", "text": "Everything else in this guide is optimization. Sunscreen is the floor. Get this right and you've already outperformed most people's entire routines."}]}]}, {"num": 4, "id": "section-4", "code": "S04", "title": "THE SKINCARE SCAM", "category": "FILTER", "short": "THE SKINCARE SCAM", "intro": [{"type": "p", "text": "Here's the uncomfortable truth: almost everything marketed to you for \"good skin\" — on social media, in ads, on shelves with elaborate packaging — is unnecessary once CTP is dialed in. Not all of it is fake. Most of it is just redundant, overpriced, or solving a problem you don't have."}], "subs": [{"title": "How to Actually Choose Products", "blocks": [{"type": "list", "ordered": false, "items": ["**Ingredients over products, always.** You already know this from Step 2 — it's the filter for everything below.", "**Look for brands that are transparent about their actual active ingredients and concentrations** — not vague \"benefits\" language. A label that says \"2% salicylic acid\" is telling you something real. A label that says \"deep cleansing glow complex\" is telling you nothing.", "**Be skeptical of words like \"glow,\" \"radiance,\" and \"detox\"** when they're not backed by a named, dosed ingredient. These words sell bottles; they don't describe chemistry.", "**Pharma-based ingredient brands** — companies with a background in pharmaceutical-grade formulation — tend to produce excellent, no-nonsense products. This is a personal preference, not gospel, but it's a pattern worth noticing: brands that come from a medical/pharma lineage tend to talk about ingredients, not vibes.", "**Disproportionate focus on sunscreen.** If you're going to spend more on one category, make it this one. A good sunscreen you'll actually wear every day is worth more than an entire shelf of serums."]}, {"type": "p", "text": "The test for any product, every time: can you find the active ingredient and its concentration on the label, and does that ingredient match a concern you actually have? If yes, it might be worth it. If the answer is \"I don't know\" to either question, you've found one of the 99%."}]}]}, {"num": 5, "id": "section-5", "code": "S05", "title": "RETINOIDS — THE MVP INGREDIENT", "category": "DEEP DIVE", "short": "RETINOIDS", "intro": [{"type": "p", "text": "If this guide has a favorite child, it's retinoids. No other single ingredient category does as much across as many concerns: acne, texture, scarring, pigmentation, and anti-aging are all addressed, at least in part, by retinoids. If you only add one active ingredient to your routine beyond Cleanse and Protect, make it this one."}], "subs": [{"title": "Why Start in Your 20s", "blocks": [{"type": "p", "text": "Retinoids are almost always framed as an anti-aging ingredient for people who are already seeing signs of aging. That framing undersells them. The earlier you start, the more you're working in *prevention* mode rather than correction — and prevention is both easier and more effective. There's no real downside to starting a low-strength retinoid routine in your 20s."}]}, {"title": "The Spectrum: OTC Retinol to Prescription Tretinoin", "blocks": [{"type": "p", "text": "Retinoids exist on a strength spectrum:"}, {"type": "list", "ordered": false, "items": ["**OTC retinol serums and creams** — widely available, lower strength, a sensible starting point for most people.", "**Pharma-grade / prescription retinoids (e.g., tretinoin)** — significantly stronger, faster-acting, and generally require a prescription. Better suited for more stubborn concerns (acne, scarring, established pigmentation) once you've adjusted to retinoids generally."]}, {"type": "p", "text": "You don't need to start at the strong end. Moving up the spectrum as your skin adapts is the right approach for almost everyone."}]}, {"title": "Safe Usage: How to Introduce Retinoids", "blocks": [{"type": "list", "ordered": false, "items": ["**Start at a low concentration** and a low frequency — 2–3 nights a week is a reasonable starting point, not nightly.", "**Buffer with moisturizer.** Applying moisturizer before or after your retinoid reduces irritation while you adjust.", "**Expect a \"purging\" or adjustment period.** Initial dryness, flaking, or a temporary increase in breakouts is common and usually settles within a few weeks. This isn't a sign to stop — it's a sign to go slower, not to quit.", "**Increase frequency gradually** as your skin tolerates it — moving from a few nights a week toward nightly use over weeks to months.", "**Patience is the actual active ingredient here.** Retinoids work over months, not days."]}]}, {"title": "The Non-Negotiable Pairing", "blocks": [{"type": "p", "text": "Retinoids increase your skin's sensitivity to UV. Using a retinoid without daily sunscreen isn't just risky — it actively works against the ingredient's own benefits, particularly for pigmentation and aging. If you take retinoids seriously, Step 3 isn't optional. It never was, but it especially isn't now."}]}]}, {"num": 6, "id": "section-6", "code": "S06", "title": "PRODUCTS, BRANDS & ROUTINES", "category": "REFERENCE", "short": "PRODUCTS & ROUTINES", "intro": [], "subs": [{"title": "Product & Brand Recommendations", "blocks": [{"type": "p", "text": "Don't overstress about brand names — by this point, you understand that ingredients matter more than logos. That said, once you find a brand that's transparent, formulates well, and is consistently available, defaulting to that brand across most of your routine is a perfectly reasonable way to simplify things."}, {"type": "p", "text": "Brands worth exploring for both treatment products and sunscreens, known for reasonably transparent, ingredient-forward formulations: **Minimalist**, **Undivated**, **Plix**, **DermaCo**, **Aqualogica**, **CeraVe**, **Cetaphil**, and **Deconstruct**. These span a range of price points and formulation styles, and most offer the core ingredients covered in this guide (retinoids, niacinamide, AHAs/BHAs, ceramides, sunscreens) at clearly labeled concentrations."}, {"type": "p", "text": "**For sunscreen specifically**, expect some trial and error. Try a few different brands and formulas — texture, finish, and how it feels under makeup or in heat all vary. The \"best\" sunscreen, scientifically, is the one you'll actually put on your face every single day without skipping it. Consistency beats the marginal SPF or formula differences between good options."}]}, {"title": "My Personal Skincare Routine", "blocks": [{"type": "p", "text": "Here's what the system looks like in practice — not as a universal prescription, but as a worked example of CTP in action, adapted to one routine."}, {"type": "list", "ordered": false, "items": ["**Morning:** Cleanse → Toner (2% glycolic acid) → Sunscreen (SPF 50+)", "**Throughout the day:** Reapply sunscreen as needed", "**Night:** Cleanse → Tretinoin (~0.5%) → Light moisturizer"]}, {"type": "p", "text": "That's the entire routine. Cleanse and Protect, every day, no exceptions. A mild AHA toner in the morning for gentle, ongoing exfoliation. Tretinoin at night as the standing treatment habit — the \"ideal skin condition\" maintenance routine described in Step 2's Post-Treatment section. Adapt the specifics to your own concerns and tolerance, but the structure — simple, consistent, sunscreen-anchored — is the point."}]}]}, {"num": 7, "id": "section-7", "code": "S07", "title": "FREQUENTLY ASKED QUESTIONS", "category": "REFERENCE", "short": "FAQ", "intro": [], "subs": [{"title": "General / CTP", "blocks": [{"type": "p", "text": "**Q: Is CTP really \"all I need,\" or is this oversimplified?** A: For the vast majority of people, yes — it's genuinely complete. Cleanse and Protect cover universal needs; Treat covers anything specific to you. The \"extra steps\" most routines add are either redundant with these three or address concerns that don't exist for that person."}, {"type": "p", "text": "**Q: I have no skin concerns — do I still need a routine?** A: Yes, but a short one: Cleanse + Protect, daily. That's it. No Treat step needed until something actually changes."}, {"type": "p", "text": "**Q: How long until I see results from a new routine?** A: Sunscreen's benefits are mostly preventive — there's nothing dramatic to \"see,\" but its absence shows up over years. For Treat ingredients, expect 4–8 weeks for early signs and 3+ months for meaningful change (longer for pigmentation and scarring)."}, {"type": "p", "text": "**Q: What's the difference between a \"cleanser\" and a \"face wash,\" really?** A: Largely a formulation and marketing distinction — \"cleanser\" products tend to be gentler and more barrier-conscious as a category, while \"face wash\" leans toward stronger, foaming, \"deep clean\" formulas. Use the label as a heuristic, then check the formula."}, {"type": "p", "text": "**Q: Can I use the same routine in summer and winter?** A: Mostly — sunscreen is non-negotiable year-round. You may want a richer moisturizer in winter and lighter in summer, but Treat actives don't need to change."}]}, {"title": "Cleansing", "blocks": [{"type": "p", "text": "**Q: Am I cleansing too much or too little?** A: Twice daily is right for most people, plus occasional extra cleanses after sweating. Tight, stripped, or irritated skin signals over-cleansing or too harsh a product."}, {"type": "p", "text": "**Q: Is double cleansing necessary?** A: Not for most people — useful for removing heavy makeup or sunscreen a single gentle cleanse won't fully remove, otherwise one proper cleanse is enough."}, {"type": "p", "text": "**Q: Why shouldn't I use a scrub if it makes my skin feel \"cleaner\"?** A: That \"clean\" feeling is often micro-abrasion of your skin barrier, not extra cleanliness. Scrubbing causes small tears that can worsen sensitivity, redness, and acne over time."}, {"type": "p", "text": "**Q: My face feels tight after cleansing — is that normal?** A: No — it usually means your cleanser is too harsh or you're over-cleansing. Move toward the \"gentle/hydrating\" end of the Step 1 hierarchy."}]}, {"title": "Treat / Ingredients", "blocks": [{"type": "p", "text": "**Q: How do I know which concern to prioritize if I have multiple?** A: Prioritize whatever's most active right now — usually acne or redness over pigmentation or aging, since those move slower. Address one or two concerns at a time."}, {"type": "p", "text": "**Q: Can I use Vitamin C and retinol in the same routine?** A: Yes, but typically not in the same application — Vitamin C in the morning, retinoid at night is the standard low-irritation approach."}, {"type": "p", "text": "**Q: How long should I use an active ingredient before deciding it's not working?** A: At least 8–12 weeks at a consistent frequency, except for acute issues like active breakouts, which can show change sooner."}, {"type": "p", "text": "**Q: What does \"patch testing\" mean and should I actually do it?** A: Applying a new product to a small area (behind the ear or jaw) for a few days before full-face use, to check for a reaction. Yes — especially for new actives or anything marketed as \"strong.\""}, {"type": "p", "text": "**Q: Is it bad to switch products/ingredients frequently?** A: Yes. Most actives need weeks to months to show effects — switching every few weeks means nothing gets enough time to work."}, {"type": "p", "text": "**Q: What's the difference between retinol, retinoids, and tretinoin?** A: \"Retinoids\" is the umbrella term. \"Retinol\" is a common, milder, OTC form. \"Tretinoin\" is a stronger, prescription-grade retinoid further along the spectrum."}, {"type": "p", "text": "**Q: How long does the retinoid \"purging\" period last, and is it normal?** A: Typically a few weeks — a normal adjustment for many people, not a sign of a \"wrong\" product. If irritation is severe, reduce frequency rather than push through."}, {"type": "p", "text": "**Q: I have sensitive skin — can I still use actives like AHAs/retinoids?** A: Yes, but start lower and slower than average, prioritizing gentler options (azelaic acid, niacinamide, lactic acid) before stronger acids or retinoids."}, {"type": "p", "text": "**Q: Do natural/home remedies work for any of these concerns?** A: A few (aloe vera for redness) have genuine mild benefits and appear in the map above. Most marketed home remedies lack meaningful evidence — and some, like lemon juice, can cause irritation or pigmentation issues."}]}, {"title": "Protect / Sunscreen", "blocks": [{"type": "p", "text": "**Q: Do I need sunscreen if I have darker skin or rarely burn?** A: Yes. Darker skin has more natural protection but isn't immune to UV damage, pigmentation, or skin cancer risk — and pigmentation specifically responds strongly to consistent sun protection."}, {"type": "p", "text": "**Q: Chemical vs. physical sunscreen — which should I actually use?** A: Physical (mineral) sunscreens are generally preferable alongside actives — gentler and effective immediately on application. Chemical sunscreens still work if that's what you'll wear consistently; the best sunscreen is the one you use daily."}, {"type": "p", "text": "**Q: Do I need sunscreen indoors or on cloudy days?** A: Yes. UV passes through clouds and windows — make it a daily habit regardless of weather or location."}, {"type": "p", "text": "**Q: Why does my sunscreen leave a white cast, and how do I fix that?** A: Common with mineral formulas due to the UV-blocking particles. Try a different formula or brand — tinted mineral sunscreens or newer micronized formulas reduce this significantly."}, {"type": "p", "text": "**Q: Is a moisturizer with SPF enough, or do I need a separate sunscreen?** A: A dedicated sunscreen is better — people apply moisturizer more thinly than a true sunscreen layer needs, which under-delivers the labeled SPF."}]}, {"title": "Scam Section / Product Choice", "blocks": [{"type": "p", "text": "**Q: How do I evaluate a new product before buying it?** A: Check the ingredient list for a named active at a meaningful concentration matching a concern you actually have. No match, or all \"benefits\" language with no substance — skip it."}, {"type": "p", "text": "**Q: Are expensive products actually better than affordable ones?** A: Not inherently. Price often reflects packaging and brand positioning more than ingredient quality or concentration — compare formulas, not price tags."}, {"type": "p", "text": "**Q: What ingredients are basically \"marketing only\" with little real benefit?** A: Watch for vague \"complexes,\" \"extracts,\" and \"botanicals\" listed without concentrations, especially as the headline ingredient. Rarely harmful, but rarely the reason a product works."}, {"type": "p", "text": "**Q: Do I need a separate toner, essence, serum, etc., or is that part of \"the scam\"?** A: These are delivery formats, not requirements. If one is your delivery method for an active you actually need (like the glycolic toner in the personal routine above), it's useful — as a category requirement on its own, it's not."}]}, {"title": "Glass Skin Specific", "blocks": [{"type": "p", "text": "**Q: What actually creates the \"glass skin\" look — is it just hydration?** A: Hydration is a big part, but so is even tone (pigmentation control), a healthy barrier (ceramides, gentle cleansing), and smooth texture (retinoids, gentle exfoliation). It's CTP working together, not one product."}, {"type": "p", "text": "**Q: Can oily skin achieve glass skin, or is it only for dry/normal skin?** A: Oily skin can absolutely achieve it — \"glass\" is about evenness and smoothness, not oil production. Lightweight hydrators and oil-appropriate moisturizers work fine."}, {"type": "p", "text": "**Q: How much of \"glass skin\" is genetics vs. routine?** A: Genetics set a baseline (pore size, tone evenness), but routine — especially sunscreen and barrier health — determines how close you get to your own ceiling. Most people sit well below their genetic ceiling due to inconsistent basics, not bad genes."}]}], "faqs": [{"category": "General / CTP", "q": "Is CTP really \"all I need,\" or is this oversimplified?", "a": "For the vast majority of people, yes — it's genuinely complete. Cleanse and Protect cover universal needs; Treat covers anything specific to you. The \"extra steps\" most routines add are either redundant with these three or address concerns that don't exist for that person."}, {"category": "General / CTP", "q": "I have no skin concerns — do I still need a routine?", "a": "Yes, but a short one: Cleanse + Protect, daily. That's it. No Treat step needed until something actually changes."}, {"category": "General / CTP", "q": "How long until I see results from a new routine?", "a": "Sunscreen's benefits are mostly preventive — there's nothing dramatic to \"see,\" but its absence shows up over years. For Treat ingredients, expect 4–8 weeks for early signs and 3+ months for meaningful change (longer for pigmentation and scarring)."}, {"category": "General / CTP", "q": "What's the difference between a \"cleanser\" and a \"face wash,\" really?", "a": "Largely a formulation and marketing distinction — \"cleanser\" products tend to be gentler and more barrier-conscious as a category, while \"face wash\" leans toward stronger, foaming, \"deep clean\" formulas. Use the label as a heuristic, then check the formula."}, {"category": "General / CTP", "q": "Can I use the same routine in summer and winter?", "a": "Mostly — sunscreen is non-negotiable year-round. You may want a richer moisturizer in winter and lighter in summer, but Treat actives don't need to change."}, {"category": "Cleansing", "q": "Am I cleansing too much or too little?", "a": "Twice daily is right for most people, plus occasional extra cleanses after sweating. Tight, stripped, or irritated skin signals over-cleansing or too harsh a product."}, {"category": "Cleansing", "q": "Is double cleansing necessary?", "a": "Not for most people — useful for removing heavy makeup or sunscreen a single gentle cleanse won't fully remove, otherwise one proper cleanse is enough."}, {"category": "Cleansing", "q": "Why shouldn't I use a scrub if it makes my skin feel \"cleaner\"?", "a": "That \"clean\" feeling is often micro-abrasion of your skin barrier, not extra cleanliness. Scrubbing causes small tears that can worsen sensitivity, redness, and acne over time."}, {"category": "Cleansing", "q": "My face feels tight after cleansing — is that normal?", "a": "No — it usually means your cleanser is too harsh or you're over-cleansing. Move toward the \"gentle/hydrating\" end of the Step 1 hierarchy."}, {"category": "Treat / Ingredients", "q": "How do I know which concern to prioritize if I have multiple?", "a": "Prioritize whatever's most active right now — usually acne or redness over pigmentation or aging, since those move slower. Address one or two concerns at a time."}, {"category": "Treat / Ingredients", "q": "Can I use Vitamin C and retinol in the same routine?", "a": "Yes, but typically not in the same application — Vitamin C in the morning, retinoid at night is the standard low-irritation approach."}, {"category": "Treat / Ingredients", "q": "How long should I use an active ingredient before deciding it's not working?", "a": "At least 8–12 weeks at a consistent frequency, except for acute issues like active breakouts, which can show change sooner."}, {"category": "Treat / Ingredients", "q": "What does \"patch testing\" mean and should I actually do it?", "a": "Applying a new product to a small area (behind the ear or jaw) for a few days before full-face use, to check for a reaction. Yes — especially for new actives or anything marketed as \"strong.\""}, {"category": "Treat / Ingredients", "q": "Is it bad to switch products/ingredients frequently?", "a": "Yes. Most actives need weeks to months to show effects — switching every few weeks means nothing gets enough time to work."}, {"category": "Treat / Ingredients", "q": "What's the difference between retinol, retinoids, and tretinoin?", "a": "\"Retinoids\" is the umbrella term. \"Retinol\" is a common, milder, OTC form. \"Tretinoin\" is a stronger, prescription-grade retinoid further along the spectrum."}, {"category": "Treat / Ingredients", "q": "How long does the retinoid \"purging\" period last, and is it normal?", "a": "Typically a few weeks — a normal adjustment for many people, not a sign of a \"wrong\" product. If irritation is severe, reduce frequency rather than push through."}, {"category": "Treat / Ingredients", "q": "I have sensitive skin — can I still use actives like AHAs/retinoids?", "a": "Yes, but start lower and slower than average, prioritizing gentler options (azelaic acid, niacinamide, lactic acid) before stronger acids or retinoids."}, {"category": "Treat / Ingredients", "q": "Do natural/home remedies work for any of these concerns?", "a": "A few (aloe vera for redness) have genuine mild benefits and appear in the map above. Most marketed home remedies lack meaningful evidence — and some, like lemon juice, can cause irritation or pigmentation issues."}, {"category": "Protect / Sunscreen", "q": "Do I need sunscreen if I have darker skin or rarely burn?", "a": "Yes. Darker skin has more natural protection but isn't immune to UV damage, pigmentation, or skin cancer risk — and pigmentation specifically responds strongly to consistent sun protection."}, {"category": "Protect / Sunscreen", "q": "Chemical vs. physical sunscreen — which should I actually use?", "a": "Physical (mineral) sunscreens are generally preferable alongside actives — gentler and effective immediately on application. Chemical sunscreens still work if that's what you'll wear consistently; the best sunscreen is the one you use daily."}, {"category": "Protect / Sunscreen", "q": "Do I need sunscreen indoors or on cloudy days?", "a": "Yes. UV passes through clouds and windows — make it a daily habit regardless of weather or location."}, {"category": "Protect / Sunscreen", "q": "Why does my sunscreen leave a white cast, and how do I fix that?", "a": "Common with mineral formulas due to the UV-blocking particles. Try a different formula or brand — tinted mineral sunscreens or newer micronized formulas reduce this significantly."}, {"category": "Protect / Sunscreen", "q": "Is a moisturizer with SPF enough, or do I need a separate sunscreen?", "a": "A dedicated sunscreen is better — people apply moisturizer more thinly than a true sunscreen layer needs, which under-delivers the labeled SPF."}, {"category": "Scam Section / Product Choice", "q": "How do I evaluate a new product before buying it?", "a": "Check the ingredient list for a named active at a meaningful concentration matching a concern you actually have. No match, or all \"benefits\" language with no substance — skip it."}, {"category": "Scam Section / Product Choice", "q": "Are expensive products actually better than affordable ones?", "a": "Not inherently. Price often reflects packaging and brand positioning more than ingredient quality or concentration — compare formulas, not price tags."}, {"category": "Scam Section / Product Choice", "q": "What ingredients are basically \"marketing only\" with little real benefit?", "a": "Watch for vague \"complexes,\" \"extracts,\" and \"botanicals\" listed without concentrations, especially as the headline ingredient. Rarely harmful, but rarely the reason a product works."}, {"category": "Scam Section / Product Choice", "q": "Do I need a separate toner, essence, serum, etc., or is that part of \"the scam\"?", "a": "These are delivery formats, not requirements. If one is your delivery method for an active you actually need (like the glycolic toner in the personal routine above), it's useful — as a category requirement on its own, it's not."}, {"category": "Glass Skin Specific", "q": "What actually creates the \"glass skin\" look — is it just hydration?", "a": "Hydration is a big part, but so is even tone (pigmentation control), a healthy barrier (ceramides, gentle cleansing), and smooth texture (retinoids, gentle exfoliation). It's CTP working together, not one product."}, {"category": "Glass Skin Specific", "q": "Can oily skin achieve glass skin, or is it only for dry/normal skin?", "a": "Oily skin can absolutely achieve it — \"glass\" is about evenness and smoothness, not oil production. Lightweight hydrators and oil-appropriate moisturizers work fine."}, {"category": "Glass Skin Specific", "q": "How much of \"glass skin\" is genetics vs. routine?", "a": "Genetics set a baseline (pore size, tone evenness), but routine — especially sunscreen and barrier health — determines how close you get to your own ceiling. Most people sit well below their genetic ceiling due to inconsistent basics, not bad genes."}]}, {"num": 8, "id": "section-8", "code": "S08", "title": "FINAL WORDS", "category": "CLOSE", "short": "FINAL WORDS", "intro": [{"type": "p", "text": "CTP is the whole system. **Cleanse** and **Protect** are universal — do them every day, for the rest of your life, no exceptions. **Treat** is customized and temporary: identify your concern, choose the ingredient that addresses it, use it correctly, and taper off once it's resolved — or settle into a light maintenance habit if your skin is already in good shape."}, {"type": "p", "text": "If you remember nothing else: wear sunscreen every single day, and consider adding a retinoid to your routine sooner rather than later. Everything else is detail."}, {"type": "p", "text": "That's genuinely all you need."}], "subs": []}], "concerns": [{"name": "Acne / Pimples", "intro": "Active breakouts are driven by a combination of excess oil, clogged pores, bacteria, and inflammation. The ingredients below address different parts of that chain:", "ingredients": [{"name": "Benzoyl peroxide", "detail": "kills acne-causing bacteria directly. Typical strengths: 5% for the face, up to 10% for body acne (back, chest), where skin is less sensitive."}, {"name": "Salicylic acid", "detail": "a BHA that exfoliates inside pores, helping clear blockages. Often available even in face washes at low concentrations for daily use."}, {"name": "Clindamycin", "detail": "a topical antibiotic, typically prescription, used for more stubborn or inflammatory acne."}, {"name": "Retinoids", "detail": "normalize skin cell turnover, preventing pores from clogging in the first place. Covered in depth later as the guide's MVP ingredient."}, {"name": "Azelaic acid", "detail": "reduces inflammation and bacteria while also helping with post-acne marks; a gentler option for sensitive skin."}], "mvpCategory": false}, {"name": "Pigmentation / Tanning (Complexion Fix)", "intro": "This is the category where one ingredient matters more than all the others combined:", "ingredients": [{"name": "Sunscreen", "detail": "by far the most important ingredient for this concern. Every other ingredient on this list is fighting against pigmentation; unprotected sun exposure actively creates more of it. Skipping sunscreen while treating pigmentation is working against yourself."}, {"name": "Hydroquinone", "detail": "a strong skin-lightening agent for stubborn dark spots, typically used short-term and often at prescription strength; not a long-term daily ingredient."}, {"name": "Lactic acid", "detail": "an AHA that gently exfoliates and brightens, well-tolerated by most skin types."}, {"name": "Vitamin C", "detail": "an antioxidant that brightens tone and helps fade dark spots over time, with the added benefit of supporting sunscreen's UV defense."}, {"name": "Retinoids", "detail": "accelerate cell turnover, helping pigmented cells shed faster and new, evener-toned skin take their place."}, {"name": "Kojic acid", "detail": "another tyrosinase-inhibiting brightening ingredient, often paired with the others above in combination formulas."}], "mvpCategory": true}, {"name": "Dry Skin", "intro": "Dryness is usually a barrier problem — either not enough moisture, not enough oil to lock it in, or both:", "ingredients": [{"name": "Ceramides", "detail": "lipids that are a natural part of your skin barrier; topical ceramides help repair and reinforce it."}, {"name": "Mineral oil", "detail": "an effective, inexpensive occlusive that locks moisture in; despite its reputation, it's well-tolerated by most skin types."}, {"name": "Petrolatum", "detail": "the gold standard occlusive, especially for very dry or compromised skin."}, {"name": "Hyaluronic acid", "detail": "a humectant that draws and holds water in the skin; works best applied to damp skin and sealed with a moisturizer."}, {"name": "Vitamin E", "detail": "an antioxidant often paired with moisturizing formulas, supporting overall skin barrier health."}], "mvpCategory": false}, {"name": "Scarring", "intro": "Scarring is the most stubborn category here, and the one most likely to need professional input:", "ingredients": [{"name": "High-strength retinoid creams", "detail": "prescription-strength retinoids can meaningfully improve texture and the appearance of scarring over months of consistent use."}, {"name": "Deep chemical peels", "detail": "professionally administered peels can address scarring more aggressively than anything available over the counter; this is a dermatologist-office category, not a home routine one."}], "mvpCategory": false}, {"name": "Redness", "intro": "Redness is typically inflammation- or sensitivity-driven:", "ingredients": [{"name": "Aloe vera", "detail": "a gentle, soothing ingredient that calms irritated skin with minimal risk of further irritation."}, {"name": "Niacinamide", "detail": "reduces inflammation and supports barrier function; one of the best-tolerated active ingredients across skin types."}, {"name": "Azelaic acid", "detail": "appears again here for its anti-inflammatory properties, doing double duty for acne and redness."}], "mvpCategory": false}, {"name": "Aging", "intro": "This category isn't just for people over 30 — and that framing matters:", "ingredients": [{"name": "Retinoids", "detail": "the single most effective anti-aging ingredient available, by a wide margin."}, {"name": "Sunscreen", "detail": "UV exposure is the single largest controllable contributor to visible aging. This isn't a secondary mention; it belongs at the top of any anti-aging conversation."}, {"name": "Copper peptides (and other peptides)", "detail": "support skin firmness and repair over time, often used alongside retinoids."}], "mvpCategory": false}], "routines": [{"title": "Routine 1 — Male, mid-20s, acne + early pigmentation", "am": "Gentle cleanser → Vitamin C serum → Sunscreen (SPF 50+)", "pm": "Gentle cleanser → Salicylic acid (2% BHA, 3–4x/week) → Niacinamide moisturizer", "logic": "Vitamin C and sunscreen handle pigmentation prevention during the day; salicylic acid targets active breakouts at night without stacking onto the AM antioxidant step."}, {"title": "Routine 2 — Male, early 30s, aging + dryness", "am": "Hydrating cleanser → Hyaluronic acid (on damp skin) → Moisturizer with ceramides → Sunscreen (SPF 50+)", "pm": "Hydrating cleanser → Retinoid (start low strength, 2–3x/week) → Rich moisturizer with petrolatum or mineral oil", "logic": "The AM routine builds and locks in hydration before sun protection; the PM retinoid addresses aging directly, buffered by a heavier moisturizer to manage dryness and minimize irritation."}, {"title": "Routine 3 — Female, late 20s, redness + sensitivity + occasional breakouts", "am": "Gentle cleanser → Niacinamide serum → Lightweight moisturizer → Sunscreen (SPF 50+, mineral)", "pm": "Gentle cleanser → Azelaic acid (2–3x/week) → Light moisturizer", "logic": "Niacinamide and azelaic acid both calm redness while azelaic acid pulls double duty on occasional breakouts; everything here is chosen for being well-tolerated by sensitive skin, with mineral sunscreen reducing irritation risk further."}], "personal": {"morning": "Cleanse → Toner (2% glycolic acid) → Sunscreen (SPF 50+)", "day": "Reapply sunscreen as needed", "night": "Cleanse → Tretinoin (~0.5%) → Light moisturizer", "note": ""}, "sunscreen": [{"title": "SPF 50 or above", "detail": "Don't go lower as a default."}, {"title": "Apply first thing after cleansing in the morning", "detail": "— before anything else, or as the final step of your AM routine depending on formula, but always as a core morning habit."}, {"title": "Reapply every ~2 hours", "detail": ", especially with continued sun exposure."}, {"title": "Reapply after sweating or water activity", "detail": "— sunscreen doesn't survive a swim or a hard workout."}, {"title": "Physical (mineral) sunscreens are generally preferable", "detail": "— they tend to be gentler on sensitive or actives-treated skin and start working immediately on application."}, {"title": "365 days a year, including indoors", "detail": "UV exposure through windows, and especially blue light/UV from extended screen exposure combined with ambient daylight, adds up. \"It's cloudy\" or \"I'm inside\" isn't a reason to skip it."}], "spectrum": [{"name": "OTC retinol serums and creams", "detail": "widely available, lower strength, a sensible starting point for most people."}, {"name": "Pharma-grade / prescription retinoids (e.g., tretinoin)", "detail": "significantly stronger, faster-acting, and generally require a prescription. Better suited for more stubborn concerns (acne, scarring, established pigmentation) once you've adjusted to retinoids generally."}], "safe": [{"title": "Start at a low concentration", "detail": "and a low frequency — 2–3 nights a week is a reasonable starting point, not nightly."}, {"title": "Buffer with moisturizer", "detail": "Applying moisturizer before or after your retinoid reduces irritation while you adjust."}, {"title": "Expect a \"purging\" or adjustment period", "detail": "Initial dryness, flaking, or a temporary increase in breakouts is common and usually settles within a few weeks. This isn't a sign to stop — it's a sign to go slower, not to quit."}, {"title": "Increase frequency gradually", "detail": "as your skin tolerates it — moving from a few nights a week toward nightly use over weeks to months."}, {"title": "Patience is the actual active ingredient here", "detail": "Retinoids work over months, not days."}]};
const IMAGES = {"crystal": "data:image/webp;base64,", "ctp": "data:image/webp;base64,", "treat": "data:image/webp;base64,", "retinoid": "data:image/webp;base64,", "protect": "data:image/webp;base64,", "routines": "data:image/webp;base64,"};

/* Name printed on the completion certificate. Edit this to personalize. */
const CERTIFICATE_NAME = "Aryan";

/* The CTP framework — drives the S00 diagram, sidebar mini-nav, pillar badges. */
const PILLARS = [
  { n: 1, key: "cleanse", label: "Cleanse", icon: "droplet", id: "section-1",
    def: "Universal and non-negotiable — gently remove dirt, oil, sweat, and sunscreen." },
  { n: 2, key: "treat", label: "Treat", icon: "dropper", id: "section-2",
    def: "The optional customization layer — match specific ingredients to a real concern." },
  { n: 3, key: "protect", label: "Protect", icon: "shield", id: "section-3",
    def: "The most important step — daily sunscreen, the highest-leverage habit in skincare." },
];
const BRANDS = ["Minimalist", "Undivated", "Plix", "DermaCo", "Aqualogica", "CeraVe", "Cetaphil", "Deconstruct"];
const SCAM_WORDS = ["glow", "radiance", "detox", "complex", "extract", "botanicals", "brightening", "deep cleansing"];
const CONCERN_ICON = { acne: "bolt", pigment: "sun", dry: "droplet", scar: "crack", red: "flame", ag: "clock" };
function concernIcon(name) {
  const n = name.toLowerCase();
  if (n.includes("acne")) return CONCERN_ICON.acne;
  if (n.includes("pigment")) return CONCERN_ICON.pigment;
  if (n.includes("dry")) return CONCERN_ICON.dry;
  if (n.includes("scar")) return CONCERN_ICON.scar;
  if (n.includes("red")) return CONCERN_ICON.red;
  return CONCERN_ICON.ag;
}

/* --------------------------------------------------------------------------
   Icon — thin-line SVG set
   -------------------------------------------------------------------------- */
function Icon({ name, className }) {
  const p = { fill: "none", stroke: "currentColor", strokeWidth: 1.6, strokeLinecap: "round", strokeLinejoin: "round" };
  const paths = {
    check: <polyline points="20 6 9 17 4 12" {...p} />,
    x: <g {...p}><line x1="18" y1="6" x2="6" y2="18" /><line x1="6" y1="6" x2="18" y2="18" /></g>,
    plus: <g {...p}><line x1="12" y1="5" x2="12" y2="19" /><line x1="5" y1="12" x2="19" y2="12" /></g>,
    minus: <line x1="5" y1="12" x2="19" y2="12" {...p} />,
    search: <g {...p}><circle cx="11" cy="11" r="7" /><line x1="21" y1="21" x2="16.65" y2="16.65" /></g>,
    "caret-down": <polyline points="6 9 12 15 18 9" {...p} />,
    "caret-right": <polyline points="9 6 15 12 9 18" {...p} />,
    arrow: <g {...p}><line x1="5" y1="12" x2="19" y2="12" /><polyline points="12 5 19 12 12 19" /></g>,
    reset: <g {...p}><polyline points="1 4 1 10 7 10" /><path d="M3.5 15a9 9 0 1 0 2.1-9.4L1 10" /></g>,
    lock: <g {...p}><rect x="4" y="11" width="16" height="9" rx="2" /><path d="M8 11V7a4 4 0 0 1 8 0v4" /></g>,
    droplet: <path d="M12 3.5c3.2 3.8 5.5 6.4 5.5 9.3A5.5 5.5 0 1 1 6.5 12.8C6.5 9.9 8.8 7.3 12 3.5z" {...p} />,
    dropper: <g {...p}><path d="M14 4.5l5.5 5.5M17 5.5l1.5 1.5" /><path d="M13 6.5l-7.8 7.8c-.3.3-.5.7-.5 1.1l-.4 2.6 2.6-.4c.4-.1.8-.2 1.1-.5L16 11.5" /></g>,
    shield: <path d="M12 3l7 3v5c0 4.5-3 7.5-7 9-4-1.5-7-4.5-7-9V6l7-3z" {...p} />,
    sun: <g {...p}><circle cx="12" cy="12" r="4" /><line x1="12" y1="2" x2="12" y2="5" /><line x1="12" y1="19" x2="12" y2="22" /><line x1="2" y1="12" x2="5" y2="12" /><line x1="19" y1="12" x2="22" y2="12" /><line x1="4.5" y1="4.5" x2="6.5" y2="6.5" /><line x1="17.5" y1="17.5" x2="19.5" y2="19.5" /><line x1="4.5" y1="19.5" x2="6.5" y2="17.5" /><line x1="17.5" y1="6.5" x2="19.5" y2="4.5" /></g>,
    clock: <g {...p}><circle cx="12" cy="12" r="8" /><polyline points="12 8 12 12 15 13" /></g>,
    calendar: <g {...p}><rect x="4" y="5" width="16" height="16" rx="2" /><line x1="4" y1="9" x2="20" y2="9" /><line x1="9" y1="3" x2="9" y2="6" /><line x1="15" y1="3" x2="15" y2="6" /></g>,
    sparkle: <path d="M12 3l1.8 5.2L19 10l-5.2 1.8L12 17l-1.8-5.2L5 10l5.2-1.8L12 3z" {...p} />,
    bolt: <polygon points="13 2 4 14 11 14 10 22 20 9 13 9 13 2" {...p} />,
    flame: <path d="M12 3c1.5 3 4 4.5 4 8a4 4 0 1 1-8 0c0-1.2.4-2 1-2.8C8.8 9.6 9 11 10.5 11 12 11 11 7 12 3z" {...p} />,
    crack: <polyline points="10 3 13 9 8 12 14 16 11 21" {...p} />,
    jar: <g {...p}><path d="M6 10h12v8a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2v-8z" /><path d="M8 10c0-2.5 1.8-4 4-4s4 1.5 4 4" /></g>,
    molecule: <g {...p}><circle cx="12" cy="12" r="2.4" /><circle cx="5" cy="7" r="1.8" /><circle cx="19" cy="7" r="1.8" /><circle cx="12" cy="20" r="1.8" /><line x1="10.2" y1="10.7" x2="6.4" y2="8" /><line x1="13.8" y1="10.7" x2="17.6" y2="8" /><line x1="12" y1="14.4" x2="12" y2="18.2" /></g>,
    beaker: <g {...p}><path d="M9 3h6M10 3v6l-4.5 8a2 2 0 0 0 1.8 3h9.4a2 2 0 0 0 1.8-3L14 9V3" /><line x1="8" y1="14" x2="16" y2="14" /></g>,
  };
  return <svg viewBox="0 0 24 24" className={className} aria-hidden="true" style={{ width: "1em", height: "1em", display: "block" }}>{paths[name] || null}</svg>;
}

/* --------------------------------------------------------------------------
   RichText — inline **bold** / *italic* / `code`
   -------------------------------------------------------------------------- */
function RichText({ text }) {
  if (!text) return null;
  const parts = useMemo(() => {
    const out = []; const re = /(\*\*[^*]+\*\*|\*[^*]+\*|`[^`]+`)/g; let last = 0, m;
    while ((m = re.exec(text)) !== null) {
      if (m.index > last) out.push({ t: "text", v: text.slice(last, m.index) });
      const tok = m[0];
      if (tok.startsWith("**")) out.push({ t: "b", v: tok.slice(2, -2) });
      else if (tok.startsWith("`")) out.push({ t: "c", v: tok.slice(1, -1) });
      else out.push({ t: "i", v: tok.slice(1, -1) });
      last = m.index + tok.length;
    }
    if (last < text.length) out.push({ t: "text", v: text.slice(last) });
    return out;
  }, [text]);
  return <>{parts.map((pt, i) => pt.t === "b" ? <strong key={i}>{pt.v}</strong> : pt.t === "i" ? <em key={i}>{pt.v}</em> : pt.t === "c" ? <code key={i} className="fp-code">{pt.v}</code> : <React.Fragment key={i}>{pt.v}</React.Fragment>)}</>;
}

/* --------------------------------------------------------------------------
   Block / Blocks
   -------------------------------------------------------------------------- */
function DataTable({ header, rows }) {
  return (
    <div className="fp-tablewrap"><table className="fp-table">
      <thead><tr>{header.map((h, i) => <th key={i}><RichText text={h} /></th>)}</tr></thead>
      <tbody>{rows.map((r, i) => <tr key={i}>{r.map((c, j) => <td key={j}><RichText text={c} /></td>)}</tr>)}</tbody>
    </table></div>
  );
}
function Block({ b }) {
  switch (b.type) {
    case "p": return <p className="fp-p"><RichText text={b.text} /></p>;
    case "h3": return <h3 className="fp-h3">{b.text}</h3>;
    case "h4": return <h4 className="fp-h4">{b.text}</h4>;
    case "quote": return <blockquote className="fp-quote"><RichText text={b.text} /></blockquote>;
    case "table": return <DataTable header={b.header} rows={b.rows} />;
    case "list": return b.ordered
      ? <ol className="fp-ol">{b.items.map((it, i) => <li key={i}><RichText text={it} /></li>)}</ol>
      : <ul className="fp-ul">{b.items.map((it, i) => <li key={i}><RichText text={it} /></li>)}</ul>;
    default: return null;
  }
}
function Blocks({ blocks }) { return <>{(blocks || []).map((b, i) => <Block key={i} b={b} />)}</>; }

