/* --------------------------------------------------------------------------
   RoutineBuilder — tabbed AM/PM icon-flow (S02 examples + S06 personal)
   -------------------------------------------------------------------------- */
function stepIcon(label) {
  const s = label.toLowerCase();
  if (s.includes("cleans")) return "droplet";
  if (s.includes("sunscreen") || s.includes("spf")) return "shield";
  if (s.includes("moistur")) return "jar";
  if (s.includes("reapply")) return "clock";
  return "dropper";
}
function Flow({ label, seq }) {
  const steps = seq.split("→").map((s) => s.trim()).filter(Boolean);
  return (
    <div className="sp-flow">
      <div className="sp-flow__lbl">{label}</div>
      <div className="sp-flow__steps">
        {steps.map((st, i) => (
          <React.Fragment key={i}>
            <div className="sp-flow__step">
              <span className="sp-flow__ic"><Icon name={stepIcon(st)} /></span>
              <span className="sp-flow__name">{st}</span>
            </div>
            {i < steps.length - 1 && <span className="sp-flow__arrow"><Icon name="caret-right" /></span>}
          </React.Fragment>
        ))}
      </div>
    </div>
  );
}
function RoutineBuilder({ routines, personal, withPersonal }) {
  const tabs = useMemo(() => {
    const t = routines.map((r, i) => ({ key: "r" + i, label: r.title.split("—")[0].trim(), sub: (r.title.split("—")[1] || "").trim(), routine: r }));
    if (withPersonal && personal) t.push({ key: "personal", label: "My Personal Routine", sub: "CTP in practice", personal });
    return t;
  }, [routines, personal, withPersonal]);
  const [tab, setTab] = useState(tabs[0].key);
  const active = tabs.find((t) => t.key === tab) || tabs[0];
  return (
    <div className="sp-rb">
      <div className="sp-rb__tabs">
        {tabs.map((t) => (
          <button key={t.key} className={"sp-rb__tab" + (tab === t.key ? " is-on" : "")} onClick={() => setTab(t.key)}>
            <b>{t.label}</b>{t.sub && <i>{t.sub}</i>}
          </button>
        ))}
      </div>
      <div className="sp-rb__body">
        {active.routine && (
          <>
            <Flow label="AM" seq={active.routine.am} />
            <Flow label="PM" seq={active.routine.pm} />
            <ScienceCallout label="LOGIC"><p className="fp-p"><RichText text={active.routine.logic} /></p></ScienceCallout>
          </>
        )}
        {active.personal && (
          <>
            <Flow label="MORNING" seq={active.personal.morning} />
            {active.personal.day && <div className="sp-rb__day"><Icon name="sun" /> Throughout the day — {active.personal.day}</div>}
            <Flow label="NIGHT" seq={active.personal.night} />
            <ScienceCallout label="LOGIC"><p className="fp-p">Cleanse and Protect every day, no exceptions. A mild AHA toner in the morning for gentle ongoing exfoliation; tretinoin at night as the standing maintenance habit. Simple, consistent, sunscreen-anchored — that's the point.</p></ScienceCallout>
          </>
        )}
      </div>
    </div>
  );
}

/* --------------------------------------------------------------------------
   SunscreenProtocol — S03 checklist + reapply timer + physical/chemical toggle
   -------------------------------------------------------------------------- */
const RULE_ICON = ["sun", "droplet", "clock", "droplet", "shield", "calendar"];
function SunscreenProtocol({ rules }) {
  const [done, setDone] = useState(() => new Set());
  const [secs, setSecs] = useState(null); // reapply countdown
  const [mode, setMode] = useState("physical");
  useEffect(() => {
    if (secs === null) return;
    if (secs <= 0) return;
    const t = setInterval(() => setSecs((s) => (s > 0 ? s - 1 : 0)), 1000);
    return () => clearInterval(t);
  }, [secs]);
  const toggle = (i) => setDone((p) => { const n = new Set(p); n.has(i) ? n.delete(i) : n.add(i); return n; });
  const fmt = (s) => `${String(Math.floor(s / 3600)).padStart(2, "0")}:${String(Math.floor((s % 3600) / 60)).padStart(2, "0")}:${String(s % 60).padStart(2, "0")}`;
  return (
    <div className="sp-sun">
      <ul className="sp-sun__list">
        {rules.map((r, i) => (
          <li key={i} className={"sp-sun__rule" + (done.has(i) ? " is-done" : "")}>
            <button className="sp-sun__box" onClick={() => toggle(i)} aria-label={r.title}>{done.has(i) && <Icon name="check" />}</button>
            <span className="sp-sun__ic"><Icon name={RULE_ICON[i] || "shield"} /></span>
            <span className="sp-sun__txt"><b>{r.title}.</b> <RichText text={r.detail} /></span>
          </li>
        ))}
      </ul>
      <div className="sp-sun__tools">
        <div className="sp-sun__timer">
          <div className="sp-sun__timerlbl">REAPPLY TIMER (~2 HRS)</div>
          {secs === null ? (
            <button className="sp-sun__apply" onClick={() => setSecs(2 * 3600)}><Icon name="droplet" /> APPLIED SUNSCREEN</button>
          ) : (
            <div className="sp-sun__count">
              <span className={"sp-sun__time" + (secs === 0 ? " is-up" : "")}>{secs === 0 ? "REAPPLY NOW" : fmt(secs)}</span>
              <button className="sp-sun__reset" onClick={() => setSecs(null)}><Icon name="reset" /></button>
            </div>
          )}
        </div>
        <div className="sp-sun__compare">
          <div className="sp-sun__toggle">
            <button className={mode === "physical" ? "is-on" : ""} onClick={() => setMode("physical")}>PHYSICAL</button>
            <button className={mode === "chemical" ? "is-on" : ""} onClick={() => setMode("chemical")}>CHEMICAL</button>
          </div>
          <p className="sp-sun__cmptext">
            {mode === "physical"
              ? "Mineral (physical) sunscreens sit on top of skin, work immediately on application, and tend to be gentler on sensitive or actives-treated skin — generally preferable."
              : "Chemical sunscreens absorb UV and can feel lighter with no white cast. Still effective — the best sunscreen is the one you'll wear every single day."}
          </p>
        </div>
      </div>
    </div>
  );
}

/* --------------------------------------------------------------------------
   ScamCheck — S04 two-question evaluation + red-flag tag cloud
   -------------------------------------------------------------------------- */
function ScamCheck() {
  const [q1, setQ1] = useState(null);
  const [q2, setQ2] = useState(null);
  const answered = q1 !== null && q2 !== null;
  const pass = q1 === true && q2 === true;
  return (
    <div className="sp-scam">
      <div className="sp-scam__head">EVALUATE ANY PRODUCT — 2 QUESTIONS</div>
      <YesNo q="Can you find the active ingredient AND its concentration on the label?" val={q1} set={setQ1} />
      <YesNo q="Does that ingredient match a concern you actually have?" val={q2} set={setQ2} />
      {answered && (
        <div className={"sp-scam__result " + (pass ? "is-good" : "is-bad")}>
          <Icon name={pass ? "check" : "x"} />
          <div>
            <b>{pass ? "Likely worth it." : "Probably part of the 99%."}</b>
            <p>{pass
              ? "It names a dosed active that targets a real concern — that's a product doing actual work. Check the concentration is meaningful and you're set."
              : "If the answer to either question is “I don't know,” you've found one of the 99% — vague benefits language with nothing dosed behind it. Walk past it."}</p>
          </div>
        </div>
      )}
      <div className="sp-scam__cloud">
        <span className="sp-scam__cloudlbl">RED-FLAG WORDS (no named, dosed ingredient behind them)</span>
        <div className="sp-scam__tags">
          {SCAM_WORDS.map((w) => <span key={w} className="sp-scam__tag">{w}</span>)}
        </div>
      </div>
    </div>
  );
}
function YesNo({ q, val, set }) {
  return (
    <div className="sp-yn">
      <span className="sp-yn__q">{q}</span>
      <div className="sp-yn__btns">
        <button className={"sp-yn__b" + (val === true ? " is-yes" : "")} onClick={() => set(true)}>YES</button>
        <button className={"sp-yn__b" + (val === false ? " is-no" : "")} onClick={() => set(false)}>NO</button>
      </div>
    </div>
  );
}

